diffs.replacement:
{
  "name": "Zogdida",
  "description": "Une application tunisienne pour réduire le gaspillage alimentaire en gérant intelligemment votre frigo.",
  "requestFramePermissions": [
    "camera",
    "notifications"
  ]
}

export enum MaturityLevel {
  VERY_FRESH = 1,
  FRESH = 2,
  MATURE = 3,
  RIPE = 4,
  OVERRIPE = 5
}

export interface FoodItem {
  id: string;
  name: string;
  purchaseDate: string;
  expiryDate: string;
  maturity: MaturityLevel;
  estimatedShelfLifeDays: number;
  isUsed: boolean;
  isWasted: boolean;
  price: number; // in TND
  weight: number; // in grams
}

export interface Recipe {
  title: string;
  ingredients: string[];
  steps: string[];
  duration: string;
  tunisianTwist: string;
}

export interface DashboardStats {
  moneySaved: number;
  foodSavedWeight: number;
  wastedItemsCount: number;
  topWastedItems: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { MaturityLevel, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const estimateShelfLife = async (name: string, maturity: MaturityLevel): Promise<number> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Estime la durée de conservation restante (en jours) pour cet aliment : "${name}" avec un état de maturité de ${maturity}/5 (1=très frais, 5=très mûr). Réponds uniquement par un chiffre entier.`,
    });
    const days = parseInt(response.text.trim());
    return isNaN(days) ? 3 : days;
  } catch (error) {
    console.error("Error estimating shelf life:", error);
    return 3;
  }
};

export const getTunisianRecipes = async (itemName: string, otherIngredients: string[]): Promise<Recipe[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Propose 3 recettes rapides tunisiennes (moins de 20 min) utilisant principalement l'ingrédient "${itemName}". Ingrédients déjà disponibles : ${otherIngredients.join(", ")}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
              steps: { type: Type.ARRAY, items: { type: Type.STRING } },
              duration: { type: Type.STRING },
              tunisianTwist: { type: Type.STRING }
            },
            required: ["title", "ingredients", "steps", "duration", "tunisianTwist"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Error fetching recipes:", error);
    return [];
  }
};

import { FoodItem, DashboardStats } from "../types";

const STORAGE_KEY_ITEMS = "zogdida_items";
const STORAGE_KEY_STATS = "zogdida_stats";

export const saveItems = (items: FoodItem[]) => {
  localStorage.setItem(STORAGE_KEY_ITEMS, JSON.stringify(items));
};

export const loadItems = (): FoodItem[] => {
  const data = localStorage.getItem(STORAGE_KEY_ITEMS);
  return data ? JSON.parse(data) : [];
};

export const saveStats = (stats: DashboardStats) => {
  localStorage.setItem(STORAGE_KEY_STATS, JSON.stringify(stats));
};

export const loadStats = (): DashboardStats => {
  const data = localStorage.getItem(STORAGE_KEY_STATS);
  return data ? JSON.parse(data) : {
    moneySaved: 0,
    foodSavedWeight: 0,
    wastedItemsCount: 0,
    topWastedItems: []
  };
};

import React, { useState } from 'react';
import { MaturityLevel, FoodItem } from '../types';
import { estimateShelfLife } from '../services/geminiService';

interface AddFoodModalProps {
  onClose: () => void;
  onAdd: (item: FoodItem) => void;
}

const AddFoodModal: React.FC<AddFoodModalProps> = ({ onClose, onAdd }) => {
  const [name, setName] = useState('');
  const [maturity, setMaturity] = useState<MaturityLevel>(MaturityLevel.FRESH);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    const shelfLife = await estimateShelfLife(name, maturity);
    const now = new Date();
    const expiry = new Date();
    expiry.setDate(now.getDate() + shelfLife);

    const newItem: FoodItem = {
      id: crypto.randomUUID(),
      name: name.trim(),
      purchaseDate: now.toISOString().split('T')[0],
      expiryDate: expiry.toISOString().split('T')[0],
      maturity,
      estimatedShelfLifeDays: shelfLife,
      isUsed: false,
      isWasted: false,
      price: Math.floor(Math.random() * 10) + 2, // Mock price 2-12 TND
      weight: (Math.floor(Math.random() * 8) + 1) * 100, // Mock weight 100-800g
    };

    onAdd(newItem);
    setLoading(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="bg-emerald-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">Ajouter un aliment</h2>
          <button onClick={onClose} className="p-2 hover:bg-emerald-500 rounded-full transition-colors">
            <i className="fa-solid fa-xmark text-lg"></i>
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nom de l'aliment</label>
            <input
              autoFocus
              type="text"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
              placeholder="ex: Tomates, Yaourt..."
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">État de maturité</label>
            <div className="flex justify-between items-center bg-slate-50 p-3 rounded-xl">
              {[1, 2, 3, 4, 5].map((level) => (
                <button
                  key={level}
                  type="button"
                  onClick={() => setMaturity(level)}
                  className={`flex flex-col items-center p-2 rounded-lg transition-all ${
                    maturity === level ? 'bg-emerald-100 text-emerald-700 scale-110 shadow-sm' : 'text-slate-400'
                  }`}
                >
                  <i className={`fa-solid fa-star ${maturity >= level ? 'text-amber-400' : 'text-slate-200'}`}></i>
                  <span className="text-[10px] mt-1 font-bold">{level}</span>
                </button>
              ))}
            </div>
            <p className="text-xs text-slate-500 mt-2 text-center">
              {maturity === 1 ? 'Très frais' : maturity === 5 ? 'Très mûr / Proche péremption' : 'Moyen'}
            </p>
          </div>

          <button
            disabled={loading}
            type="submit"
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2"
          >
            {loading ? (
              <i className="fa-solid fa-circle-notch animate-spin"></i>
            ) : (
              <><i className="fa-solid fa-plus"></i> Ajouter au frigo</>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddFoodModal;

import React, { useEffect, useState } from 'react';
import { Recipe, FoodItem } from '../types';
import { getTunisianRecipes } from '../services/geminiService';

interface RecipeModalProps {
  item: FoodItem;
  otherIngredients: string[];
  onClose: () => void;
}

const RecipeModal: React.FC<RecipeModalProps> = ({ item, otherIngredients, onClose }) => {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchRecipes = async () => {
      const data = await getTunisianRecipes(item.name, otherIngredients);
      setRecipes(data);
      setLoading(false);
    };
    fetchRecipes();
  }, [item.name, otherIngredients]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
      <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
        <div className="bg-rose-500 p-6 text-white flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-xl font-bold">Cuisiner : {item.name}</h2>
            <p className="text-sm opacity-90">Sauvez cet ingrédient avec ces recettes rapides</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-rose-400 rounded-full transition-colors">
            <i className="fa-solid fa-xmark text-lg"></i>
          </button>
        </div>

        <div className="overflow-y-auto p-6 space-y-6">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-rose-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-slate-500 font-medium">Génération de recettes tunisiennes...</p>
            </div>
          ) : recipes.length > 0 ? (
            recipes.map((recipe, idx) => (
              <div key={idx} className="bg-slate-50 rounded-2xl p-5 border border-slate-100 shadow-sm">
                <div className="flex justify-between items-start mb-4">
                  <h3 className="text-lg font-bold text-rose-600">{recipe.title}</h3>
                  <span className="bg-white px-3 py-1 rounded-full text-xs font-bold text-slate-600 shadow-sm flex items-center gap-1">
                    <i className="fa-regular fa-clock"></i> {recipe.duration}
                  </span>
                </div>

                <div className="grid md:grid-cols-2 gap-6">
                  <div>
                    <h4 className="text-sm font-bold text-slate-700 uppercase tracking-wider mb-2">Ingrédients</h4>
                    <ul className="text-sm text-slate-600 space-y-1">
                      {recipe.ingredients.map((ing, i) => (
                        <li key={i} className="flex items-center gap-2">
                          <i className="fa-solid fa-check text-rose-400 text-[10px]"></i> {ing}
                        </li>
                      ))}
                    </ul>
                  </div>
                  <div>
                    <h4 className="text-sm font-bold text-slate-700 uppercase tracking-wider mb-2">Instructions</h4>
                    <ol className="text-sm text-slate-600 space-y-2">
                      {recipe.steps.map((step, i) => (
                        <li key={i} className="flex gap-2">
                          <span className="font-bold text-rose-400 shrink-0">{i + 1}.</span> {step}
                        </li>
                      ))}
                    </ol>
                  </div>
                </div>

                <div className="mt-4 pt-4 border-t border-slate-200">
                  <p className="text-sm italic text-slate-700 flex items-center gap-2">
                    <i className="fa-solid fa-pepper-hot text-rose-500"></i>
                    <strong>Le secret Tunisien :</strong> {recipe.tunisianTwist}
                  </p>
                </div>
              </div>
            ))
          ) : (
            <p className="text-center py-10 text-slate-500">Aucune recette trouvée. Essayez un autre ingrédient.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default RecipeModal;

import React, { useState, useEffect, useMemo } from 'react';
import { FoodItem, DashboardStats, MaturityLevel } from './types';
import { loadItems, saveItems, loadStats, saveStats } from './utils/storage';
import AddFoodModal from './components/AddFoodModal';
import RecipeModal from './components/RecipeModal';

const App: React.FC = () => {
  const [items, setItems] = useState<FoodItem[]>([]);
  const [stats, setStats] = useState<DashboardStats>(loadStats());
  const [view, setView] = useState<'home' | 'stats' | 'list'>('home');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [selectedRecipeItem, setSelectedRecipeItem] = useState<FoodItem | null>(null);

  useEffect(() => {
    setItems(loadItems());
  }, []);

  useEffect(() => {
    saveItems(items);
  }, [items]);

  useEffect(() => {
    saveStats(stats);
  }, [stats]);

  const sortedItems = useMemo(() => {
    return [...items]
      .filter(item => !item.isUsed && !item.isWasted)
      .sort((a, b) => new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime());
  }, [items]);

  const shoppingListItems = useMemo(() => {
    // Basic logic: items about to expire or already consumed/wasted are added back
    const lowItems = items.filter(i => {
      const daysLeft = Math.ceil((new Date(i.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
      return daysLeft < 2 && !i.isUsed && !i.isWasted;
    });
    return Array.from(new Set(lowItems.map(i => i.name)));
  }, [items]);

  const handleAddItem = (newItem: FoodItem) => {
    setItems(prev => [newItem, ...prev]);
  };

  const markAsUsed = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;

    setItems(prev => prev.map(i => i.id === id ? { ...i, isUsed: true } : i));
    setStats(prev => ({
      ...prev,
      moneySaved: prev.moneySaved + item.price,
      foodSavedWeight: prev.foodSavedWeight + item.weight
    }));
  };

  const markAsWasted = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;

    setItems(prev => prev.map(i => i.id === id ? { ...i, isWasted: true } : i));
    setStats(prev => {
      const newTopWasted = [...prev.topWastedItems];
      if (!newTopWasted.includes(item.name)) newTopWasted.push(item.name);
      return {
        ...prev,
        wastedItemsCount: prev.wastedItemsCount + 1,
        topWastedItems: newTopWasted.slice(-5)
      };
    });
  };

  const getUrgencyColor = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'bg-slate-500';
    if (daysLeft < 2) return 'bg-rose-500';
    if (daysLeft < 4) return 'bg-amber-500';
    return 'bg-emerald-500';
  };

  const getUrgencyText = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'Périmé';
    if (daysLeft === 0) return "Aujourd'hui";
    if (daysLeft === 1) return 'Demain';
    return `${daysLeft} jours`;
  };

  return (
    <div className="min-h-screen pb-24 max-w-lg mx-auto bg-slate-50">
      {/* Header */}
      <header className="p-6 pb-2 flex justify-between items-center sticky top-0 bg-slate-50/80 backdrop-blur-md z-40">
        <div>
          <h1 className="text-3xl font-black text-emerald-700 tracking-tight">Zogdida</h1>
          <p className="text-xs font-medium text-slate-500 uppercase tracking-widest">Tunisian Food Saver</p>
        </div>
        <button 
          onClick={() => setIsAddModalOpen(true)}
          className="bg-emerald-600 text-white w-12 h-12 rounded-2xl shadow-lg shadow-emerald-200 flex items-center justify-center hover:bg-emerald-700 transition-all active:scale-90"
        >
          <i className="fa-solid fa-plus text-xl"></i>
        </button>
      </header>

      <main className="px-6 py-4">
        {view === 'home' && (
          <div className="space-y-6">
            <section>
              <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
                <i className="fa-solid fa-refrigerator text-emerald-600"></i> Mon Frigo
              </h2>
              {sortedItems.length === 0 ? (
                <div className="bg-white rounded-3xl p-10 text-center border-2 border-dashed border-slate-200">
                  <div className="bg-slate-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fa-solid fa-basket-shopping text-slate-400 text-2xl"></i>
                  </div>
                  <p className="text-slate-500 font-medium">Votre frigo est vide.<br/>Commencez par ajouter un aliment !</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {sortedItems.map(item => (
                    <div key={item.id} className="bg-white rounded-3xl p-4 shadow-sm border border-slate-100 group animate-in slide-in-from-bottom-4 duration-300">
                      <div className="flex justify-between items-center mb-3">
                        <div>
                          <h3 className="font-bold text-slate-800 text-lg capitalize">{item.name}</h3>
                          <div className="flex items-center gap-1 mt-1">
                            {[1, 2, 3, 4, 5].map(lvl => (
                              <i key={lvl} className={`fa-solid fa-star text-[10px] ${item.maturity >= lvl ? 'text-amber-400' : 'text-slate-200'}`}></i>
                            ))}
                          </div>
                        </div>
                        <div className={`px-3 py-1 rounded-full text-white text-[10px] font-black uppercase tracking-wider ${getUrgencyColor(item.expiryDate)}`}>
                          {getUrgencyText(item.expiryDate)}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => markAsUsed(item.id)}
                          className="flex-1 bg-emerald-50 text-emerald-700 py-3 rounded-2xl text-sm font-bold flex items-center justify-center gap-2 hover:bg-emerald-100 transition-colors"
                        >
                          <i className="fa-solid fa-check"></i> Utilisé
                        </button>
                        <button 
                          onClick={() => setSelectedRecipeItem(item)}
                          className="w-12 h-12 bg-rose-50 text-rose-600 rounded-2xl flex items-center justify-center hover:bg-rose-100 transition-colors"
                          title="Recettes"
                        >
                          <i className="fa-solid fa-utensils"></i>
                        </button>
                        <button 
                          onClick={() => markAsWasted(item.id)}
                          className="w-12 h-12 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 transition-colors"
                          title="Gaspillé"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        )}

        {view === 'stats' && (
          <div className="space-y-6">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-chart-line text-emerald-600"></i> Impact Zogdida
            </h2>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-emerald-600 rounded-3xl p-5 text-white shadow-lg shadow-emerald-200">
                <div className="text-3xl font-black mb-1">{stats.moneySaved} <span className="text-sm font-normal">TND</span></div>
                <div className="text-xs font-medium opacity-80 uppercase tracking-wider">Économies</div>
              </div>
              <div className="bg-amber-500 rounded-3xl p-5 text-white shadow-lg shadow-amber-200">
                <div className="text-3xl font-black mb-1">{(stats.foodSavedWeight / 1000).toFixed(1)} <span className="text-sm font-normal">kg</span></div>
                <div className="text-xs font-medium opacity-80 uppercase tracking-wider">Sauvé</div>
              </div>
            </div>

            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
              <h3 className="font-bold text-slate-700 mb-4 uppercase text-xs tracking-widest">Aliments les plus gaspillés</h3>
              {stats.topWastedItems.length > 0 ? (
                <ul className="space-y-3">
                  {stats.topWastedItems.map((name, i) => (
                    <li key={i} className="flex items-center gap-3">
                      <span className="w-6 h-6 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center text-[10px] font-bold">{i+1}</span>
                      <span className="text-slate-600 font-medium capitalize">{name}</span>
                    </li>
                  ))}
                </ul>
              ) : (
                <p className="text-center py-6 text-slate-400 text-sm">Pas encore de statistiques de gaspillage. Bravo !</p>
              )}
            </div>
          </div>
        )}

        {view === 'list' && (
          <div className="space-y-6">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <i className="fa-solid fa-list-check text-emerald-600"></i> Liste de courses intelligente
            </h2>
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
              <p className="text-xs text-slate-400 mb-4 italic">Générée automatiquement pour éviter les achats inutiles.</p>
              {shoppingListItems.length > 0 ? (
                <div className="space-y-3">
                  {shoppingListItems.map((name, i) => (
                    <div key={i} className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl">
                      <input type="checkbox" className="w-5 h-5 rounded-lg border-slate-300 text-emerald-600 focus:ring-emerald-500" />
                      <span className="text-slate-700 font-medium capitalize">{name}</span>
                    </div>
                  ))}
                  <button className="w-full mt-4 py-3 text-emerald-600 font-bold text-sm bg-emerald-50 rounded-xl hover:bg-emerald-100 transition-colors">
                    <i className="fa-solid fa-plus mr-2"></i> Ajouter manuellement
                  </button>
                </div>
              ) : (
                <div className="text-center py-10">
                  <i className="fa-solid fa-clipboard-check text-slate-300 text-4xl mb-3"></i>
                  <p className="text-slate-500">Rien à acheter pour le moment !</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm glass rounded-full shadow-2xl p-2 flex justify-between items-center z-50">
        <button 
          onClick={() => setView('home')}
          className={`flex-1 py-3 rounded-full flex flex-col items-center gap-1 transition-all ${view === 'home' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400'}`}
        >
          <i className="fa-solid fa-house"></i>
          <span className="text-[10px] font-bold">Frigo</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex-1 py-3 rounded-full flex flex-col items-center gap-1 transition-all ${view === 'list' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400'}`}
        >
          <i className="fa-solid fa-cart-shopping"></i>
          <span className="text-[10px] font-bold">Courses</span>
        </button>
        <button 
          onClick={() => setView('stats')}
          className={`flex-1 py-3 rounded-full flex flex-col items-center gap-1 transition-all ${view === 'stats' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400'}`}
        >
          <i className="fa-solid fa-chart-pie"></i>
          <span className="text-[10px] font-bold">Score</span>
        </button>
      </nav>

      {isAddModalOpen && (
        <AddFoodModal 
          onClose={() => setIsAddModalOpen(false)} 
          onAdd={handleAddItem} 
        />
      )}

      {selectedRecipeItem && (
        <RecipeModal 
          item={selectedRecipeItem} 
          otherIngredients={sortedItems.map(i => i.name)}
          onClose={() => setSelectedRecipeItem(null)} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MaturityLevel {
  VERY_FRESH = 1,
  FRESH = 2,
  MATURE = 3,
  RIPE = 4,
  OVERRIPE = 5
}

export type FoodCategory = 'Légume' | 'Fruit' | 'Produit laitier' | 'Charcuterie' | 'Viande/Poisson' | 'Épicerie' | 'Autre';

export interface FoodItem {
  id: string;
  name: string;
  category: FoodCategory;
  purchaseDate: string;
  expiryDate: string;
  maturity: MaturityLevel;
  estimatedShelfLifeDays: number;
  isUsed: boolean;
  isWasted: boolean;
  price: number; // in TND
  weight: number; // in grams
}

export interface Recipe {
  title: string;
  ingredients: string[];
  steps: string[];
  duration: string;
  tunisianTwist: string;
}

export interface DashboardStats {
  moneySaved: number;
  foodSavedWeight: number;
  wastedItemsCount: number;
  topWastedItems: string[];
}

import React, { useState } from 'react';
import { MaturityLevel, FoodItem, FoodCategory } from '../types';
import { estimateShelfLife } from '../services/geminiService';

interface AddFoodModalProps {
  onClose: () => void;
  onAdd: (item: FoodItem) => void;
}

const CATEGORIES: { label: FoodCategory; icon: string }[] = [
  { label: 'Légume', icon: 'fa-carrot' },
  { label: 'Fruit', icon: 'fa-apple-whole' },
  { label: 'Produit laitier', icon: 'fa-cheese' },
  { label: 'Charcuterie', icon: 'fa-bacon' },
  { label: 'Viande/Poisson', icon: 'fa-fish' },
  { label: 'Épicerie', icon: 'fa-jar' },
  { label: 'Autre', icon: 'fa-box' },
];

const AddFoodModal: React.FC<AddFoodModalProps> = ({ onClose, onAdd }) => {
  const [name, setName] = useState('');
  const [category, setCategory] = useState<FoodCategory>('Légume');
  const [purchaseDate, setPurchaseDate] = useState(new Date().toISOString().split('T')[0]);
  const [maturity, setMaturity] = useState<MaturityLevel>(MaturityLevel.FRESH);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    const shelfLife = await estimateShelfLife(name, maturity);
    const pDate = new Date(purchaseDate);
    const expiry = new Date(pDate);
    expiry.setDate(pDate.getDate() + shelfLife);

    const newItem: FoodItem = {
      id: crypto.randomUUID(),
      name: name.trim(),
      category,
      purchaseDate,
      expiryDate: expiry.toISOString().split('T')[0],
      maturity,
      estimatedShelfLifeDays: shelfLife,
      isUsed: false,
      isWasted: false,
      price: Math.floor(Math.random() * 8) + 3, // Mock price 3-11 TND
      weight: (Math.floor(Math.random() * 5) + 2) * 100, // Mock weight 200-600g
    };

    onAdd(newItem);
    setLoading(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="bg-emerald-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">Ajouter un aliment</h2>
          <button onClick={onClose} className="p-2 hover:bg-emerald-500 rounded-full transition-colors">
            <i className="fa-solid fa-xmark text-lg"></i>
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto max-h-[80vh]">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Nom du produit</label>
            <input
              autoFocus
              type="text"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
              placeholder="ex: Couscous, Tomates..."
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mb-2">Catégorie</label>
            <div className="grid grid-cols-3 gap-2">
              {CATEGORIES.map((cat) => (
                <button
                  key={cat.label}
                  type="button"
                  onClick={() => setCategory(cat.label)}
                  className={`flex flex-col items-center justify-center p-2 rounded-xl border-2 transition-all ${
                    category === cat.label 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                      : 'border-slate-100 text-slate-400 grayscale'
                  }`}
                >
                  <i className={`fa-solid ${cat.icon} text-lg mb-1`}></i>
                  <span className="text-[10px] font-bold leading-tight text-center">{cat.label}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Date d'achat</label>
              <input
                type="date"
                required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 text-sm outline-none"
                value={purchaseDate}
                onChange={(e) => setPurchaseDate(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Maturité (1-5)</label>
              <div className="flex items-center gap-1 justify-between bg-slate-50 p-2 rounded-xl">
                {[1, 2, 3, 4, 5].map((level) => (
                  <button
                    key={level}
                    type="button"
                    onClick={() => setMaturity(level)}
                    className={`transition-all ${maturity >= level ? 'text-amber-400' : 'text-slate-200'}`}
                  >
                    <i className="fa-solid fa-star text-sm"></i>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <button
            disabled={loading}
            type="submit"
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2 mt-2"
          >
            {loading ? (
              <i className="fa-solid fa-circle-notch animate-spin"></i>
            ) : (
              <><i className="fa-solid fa-bolt"></i> Ajouter en 10s</>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddFoodModal;

import React, { useState, useEffect, useMemo } from 'react';
import { FoodItem, DashboardStats, MaturityLevel } from './types';
import { loadItems, saveItems, loadStats, saveStats } from './utils/storage';
import AddFoodModal from './components/AddFoodModal';
import RecipeModal from './components/RecipeModal';

const App: React.FC = () => {
  const [items, setItems] = useState<FoodItem[]>([]);
  const [stats, setStats] = useState<DashboardStats>(loadStats());
  const [view, setView] = useState<'home' | 'stats' | 'list' | 'recipes'>('home');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [selectedRecipeItem, setSelectedRecipeItem] = useState<FoodItem | null>(null);

  useEffect(() => {
    setItems(loadItems());
    // Request notification permission on load
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    saveItems(items);
  }, [items]);

  useEffect(() => {
    saveStats(stats);
  }, [stats]);

  // Logic: Items expiring in < 3 days are high risk
  const sortedItems = useMemo(() => {
    return [...items]
      .filter(item => !item.isUsed && !item.isWasted)
      .sort((a, b) => {
        const timeA = new Date(a.expiryDate).getTime();
        const timeB = new Date(b.expiryDate).getTime();
        return timeA - timeB;
      });
  }, [items]);

  const urgentItems = useMemo(() => {
    return sortedItems.filter(item => {
      const daysLeft = Math.ceil((new Date(item.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
      return daysLeft <= 3;
    });
  }, [sortedItems]);

  const shoppingListItems = useMemo(() => {
    const expiredOrUsedNames = items
      .filter(i => i.isUsed || i.isWasted)
      .map(i => i.name);

    const currentlyInFridgeNames = sortedItems.map(i => i.name);

    // Suggest items that we usually have but aren't currently "fresh" in fridge
    const suggestions = Array.from(new Set(expiredOrUsedNames))
      .filter(name => !currentlyInFridgeNames.includes(name));

    return suggestions;
  }, [items, sortedItems]);

  const handleAddItem = (newItem: FoodItem) => {
    setItems(prev => [newItem, ...prev]);
  };

  const markAsUsed = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;

    setItems(prev => prev.map(i => i.id === id ? { ...i, isUsed: true } : i));
    setStats(prev => ({
      ...prev,
      moneySaved: prev.moneySaved + item.price,
      foodSavedWeight: prev.foodSavedWeight + item.weight
    }));
  };

  const markAsWasted = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;

    setItems(prev => prev.map(i => i.id === id ? { ...i, isWasted: true } : i));
    setStats(prev => {
      const newTopWasted = [...prev.topWastedItems];
      if (!newTopWasted.includes(item.name)) newTopWasted.push(item.name);
      return {
        ...prev,
        wastedItemsCount: prev.wastedItemsCount + 1,
        topWastedItems: newTopWasted.slice(-5)
      };
    });
  };

  const getUrgencyColor = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'bg-slate-500';
    if (daysLeft < 2) return 'bg-rose-600 shadow-lg shadow-rose-200 animate-pulse';
    if (daysLeft < 4) return 'bg-amber-500 shadow-md shadow-amber-100';
    return 'bg-emerald-500 shadow-sm shadow-emerald-100';
  };

  const getUrgencyText = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'Périmé';
    if (daysLeft === 0) return "Urgent : Aujourd'hui";
    if (daysLeft === 1) return 'Urgent : Demain';
    return `${daysLeft} jours restants`;
  };

  const getCategoryIcon = (cat: string) => {
    switch (cat) {
      case 'Légume': return 'fa-carrot';
      case 'Fruit': return 'fa-apple-whole';
      case 'Produit laitier': return 'fa-cheese';
      case 'Charcuterie': return 'fa-bacon';
      case 'Viande/Poisson': return 'fa-fish';
      default: return 'fa-box';
    }
  };

  return (
    <div className="min-h-screen pb-32 max-w-lg mx-auto bg-slate-50 relative overflow-x-hidden">
      {/* Header */}
      <header className="p-6 pb-2 flex justify-between items-center sticky top-0 bg-slate-50/90 backdrop-blur-xl z-40 border-b border-slate-100">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center text-white shadow-lg">
            <i className="fa-solid fa-leaf text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">Zogdida</h1>
            <p className="text-[10px] font-bold text-emerald-600 uppercase tracking-[0.2em]">Anti-Gaspillage TN</p>
          </div>
        </div>
        <button 
          onClick={() => setIsAddModalOpen(true)}
          className="bg-emerald-600 text-white w-12 h-12 rounded-2xl shadow-xl shadow-emerald-200 flex items-center justify-center hover:bg-emerald-700 transition-all active:scale-90"
        >
          <i className="fa-solid fa-plus text-xl"></i>
        </button>
      </header>

      <main className="px-5 py-6">
        {view === 'home' && (
          <div className="space-y-6">
            <section>
              <div className="flex justify-between items-end mb-5">
                <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
                  <i className="fa-solid fa-snowflake text-sky-400"></i> Mon Frigo
                </h2>
                <span className="text-xs font-bold text-slate-400">{sortedItems.length} produits</span>
              </div>

              {sortedItems.length === 0 ? (
                <div className="bg-white rounded-[2.5rem] p-12 text-center shadow-sm border border-slate-100">
                  <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                    <i className="fa-solid fa-basket-shopping text-slate-300 text-3xl"></i>
                  </div>
                  <h3 className="font-bold text-slate-700 mb-1">Votre frigo est vide</h3>
                  <p className="text-slate-400 text-sm">Ajoutez vos aliments pour commencer à économiser.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {sortedItems.map(item => (
                    <div key={item.id} className="bg-white rounded-3xl p-5 shadow-sm border border-slate-100 group transition-all hover:shadow-md animate-in slide-in-from-bottom-6 duration-500">
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex gap-4">
                          <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 shrink-0">
                            <i className={`fa-solid ${getCategoryIcon(item.category)} text-xl`}></i>
                          </div>
                          <div>
                            <h3 className="font-black text-slate-800 text-lg capitalize leading-tight">{item.name}</h3>
                            <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">{item.category}</p>
                          </div>
                        </div>
                        <div className={`px-3 py-1.5 rounded-xl text-white text-[10px] font-black uppercase tracking-wider ${getUrgencyColor(item.expiryDate)}`}>
                          {getUrgencyText(item.expiryDate)}
                        </div>
                      </div>

                      <div className="flex items-center gap-2 mt-2">
                        <button 
                          onClick={() => markAsUsed(item.id)}
                          className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl text-xs font-black flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100"
                        >
                          <i className="fa-solid fa-check-double"></i> CONSOMMÉ
                        </button>
                        <button 
                          onClick={() => setSelectedRecipeItem(item)}
                          className="w-12 h-12 bg-rose-50 text-rose-600 rounded-2xl flex items-center justify-center hover:bg-rose-100 transition-all"
                        >
                          <i className="fa-solid fa-mortar-pestle"></i>
                        </button>
                        <button 
                          onClick={() => markAsWasted(item.id)}
                          className="w-12 h-12 bg-slate-50 text-slate-300 rounded-2xl flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 transition-all"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        )}

        {view === 'recipes' && (
          <div className="space-y-6">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2 mb-4">
              <i className="fa-solid fa-kitchen-set text-rose-500"></i> Recettes Anti-Gaspi
            </h2>

            {urgentItems.length > 0 ? (
              <div className="space-y-4">
                <p className="text-sm text-slate-500 bg-rose-50 p-4 rounded-2xl border border-rose-100 italic">
                  Vous avez <strong>{urgentItems.length}</strong> produits à utiliser rapidement. Voici des idées tunisiennes :
                </p>
                {urgentItems.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setSelectedRecipeItem(item)}
                    className="w-full text-left bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between hover:border-rose-300 transition-all group"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-2xl bg-rose-50 text-rose-500 flex items-center justify-center">
                        <i className="fa-solid fa-utensils"></i>
                      </div>
                      <div>
                        <h4 className="font-bold text-slate-800 capitalize">Recette avec {item.name}</h4>
                        <p className="text-[10px] text-slate-400 uppercase tracking-widest">Tunisien • Rapide</p>
                      </div>
                    </div>
                    <i className="fa-solid fa-chevron-right text-slate-200 group-hover:translate-x-1 transition-all"></i>
                  </button>
                ))}
              </div>
            ) : (
              <div className="bg-white rounded-3xl p-10 text-center border-2 border-dashed border-slate-200">
                <i className="fa-solid fa-face-smile text-amber-400 text-4xl mb-4"></i>
                <p className="text-slate-500 font-medium">Pas d'urgences alimentaires !<br/>Vos produits sont encore bien frais.</p>
              </div>
            )}
          </div>
        )}

        {view === 'stats' && (
          <div className="space-y-6">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2 mb-5">
              <i className="fa-solid fa-trophy text-amber-400"></i> Score & Impact
            </h2>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-emerald-600 rounded-[2rem] p-6 text-white shadow-xl shadow-emerald-100">
                <div className="text-4xl font-black mb-1">{stats.moneySaved} <span className="text-sm font-normal">DT</span></div>
                <div className="text-[10px] font-black uppercase tracking-widest opacity-80">Économies</div>
              </div>
              <div className="bg-amber-500 rounded-[2rem] p-6 text-white shadow-xl shadow-amber-100">
                <div className="text-4xl font-black mb-1">{(stats.foodSavedWeight / 1000).toFixed(1)} <span className="text-sm font-normal">kg</span></div>
                <div className="text-[10px] font-black uppercase tracking-widest opacity-80">Nourriture sauvée</div>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] p-7 shadow-sm border border-slate-100">
              <h3 className="font-black text-slate-800 mb-6 uppercase text-xs tracking-[0.2em] flex items-center gap-2">
                <i className="fa-solid fa-triangle-exclamation text-rose-500"></i> Historique des Pertes
              </h3>
              {stats.topWastedItems.length > 0 ? (
                <ul className="space-y-4">
                  {stats.topWastedItems.map((name, i) => (
                    <li key={i} className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <span className="w-8 h-8 rounded-xl bg-rose-50 text-rose-500 flex items-center justify-center text-xs font-black">{i+1}</span>
                        <span className="text-slate-700 font-bold capitalize">{name}</span>
                      </div>
                      <span className="text-[10px] font-black text-rose-400">À RÉDUIRE</span>
                    </li>
                  ))}
                </ul>
              ) : (
                <div className="text-center py-4">
                  <p className="text-emerald-500 font-black text-sm">ZÉRO GASPILLAGE !</p>
                  <p className="text-slate-400 text-xs mt-1">Continuez comme ça, l'expert !</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'list' && (
          <div className="space-y-6">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2 mb-5">
              <i className="fa-solid fa-clipboard-list text-emerald-600"></i> Liste Intelligente
            </h2>
            <div className="bg-white rounded-[2rem] p-7 shadow-sm border border-slate-100">
              <div className="flex items-center gap-2 mb-6">
                <div className="bg-emerald-50 text-emerald-600 text-[10px] font-black px-3 py-1 rounded-full">AUTO-GÉNÉRÉ</div>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Basé sur vos habitudes</p>
              </div>

              {shoppingListItems.length > 0 ? (
                <div className="space-y-3">
                  {shoppingListItems.map((name, i) => (
                    <div key={i} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl group transition-all">
                      <div className="w-6 h-6 rounded-lg border-2 border-emerald-400 flex items-center justify-center group-hover:bg-emerald-400 transition-all cursor-pointer">
                        <i className="fa-solid fa-check text-white text-[10px]"></i>
                      </div>
                      <span className="text-slate-700 font-bold capitalize flex-1">{name}</span>
                    </div>
                  ))}
                  <button className="w-full mt-6 py-4 text-emerald-600 font-black text-xs bg-emerald-50 rounded-2xl hover:bg-emerald-100 transition-all flex items-center justify-center gap-2">
                    <i className="fa-solid fa-plus"></i> AJOUTER MANUELLEMENT
                  </button>
                </div>
              ) : (
                <div className="text-center py-10">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fa-solid fa-check text-slate-200 text-2xl"></i>
                  </div>
                  <p className="text-slate-400 font-bold">Rien à acheter pour l'instant.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Navigation - 4 Tabs */}
      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[92%] max-w-sm glass rounded-[2.5rem] shadow-2xl p-2.5 flex justify-between items-center z-50 border border-white/50">
        <button 
          onClick={() => setView('home')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'home' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-refrigerator text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Frigo</span>
        </button>
        <button 
          onClick={() => setView('recipes')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'recipes' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-mortar-pestle text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Recettes</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'list' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-cart-shopping text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Courses</span>
        </button>
        <button 
          onClick={() => setView('stats')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'stats' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-chart-simple text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Impact</span>
        </button>
      </nav>

      {isAddModalOpen && (
        <AddFoodModal 
          onClose={() => setIsAddModalOpen(false)} 
          onAdd={handleAddItem} 
        />
      )}

      {selectedRecipeItem && (
        <RecipeModal 
          item={selectedRecipeItem} 
          otherIngredients={sortedItems.map(i => i.name)}
          onClose={() => setSelectedRecipeItem(null)} 
        />
      )}
    </div>
  );
};

export default App;

