import { GoogleGenAI, Type } from "@google/genai";
import { MaturityLevel, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const estimateShelfLife = async (name: string, freshness: MaturityLevel): Promise<number> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Estime la durée de conservation restante (en jours) pour cet aliment : "${name}" avec un niveau de fraîcheur de ${freshness}/5 (5=parfaitement frais/neuf, 1=doit être consommé très rapidement). Réponds uniquement par un chiffre entier.`,
    });
    const days = parseInt(response.text.trim());
    return isNaN(days) ? 3 : days;
  } catch (error) {
    console.error("Error estimating shelf life:", error);
    return 3;
  }
};

export const getTunisianRecipes = async (itemName: string, otherIngredients: string[]): Promise<Recipe[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Propose 3 recettes rapides tunisiennes (moins de 20 min) mettant en valeur l'ingrédient spécifique : "${itemName}". Propose des recettes simples pour cet ingrédient seul ou en plat principal. Ingrédients secondaires éventuellement disponibles en cuisine tunisienne : ${otherIngredients.join(", ")}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
              steps: { type: Type.ARRAY, items: { type: Type.STRING } },
              duration: { type: Type.STRING },
              tunisianTwist: { type: Type.STRING }
            },
            required: ["title", "ingredients", "steps", "duration", "tunisianTwist"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Error fetching recipes:", error);
    return [];
  }
};

import React, { useState } from 'react';
import { MaturityLevel, FoodItem, FoodCategory } from '../types';
import { estimateShelfLife } from '../services/geminiService';

interface AddFoodModalProps {
  onClose: () => void;
  onAdd: (item: FoodItem) => void;
}

const CATEGORIES: { label: FoodCategory; icon: string }[] = [
  { label: 'Légume', icon: 'fa-carrot' },
  { label: 'Fruit', icon: 'fa-apple-whole' },
  { label: 'Produit laitier', icon: 'fa-cheese' },
  { label: 'Charcuterie', icon: 'fa-bacon' },
  { label: 'Viande/Poisson', icon: 'fa-fish' },
  { label: 'Épicerie', icon: 'fa-jar' },
  { label: 'Autre', icon: 'fa-box' },
];

const AddFoodModal: React.FC<AddFoodModalProps> = ({ onClose, onAdd }) => {
  const [name, setName] = useState('');
  const [category, setCategory] = useState<FoodCategory>('Légume');
  const [purchaseDate, setPurchaseDate] = useState(new Date().toISOString().split('T')[0]);
  const [freshness, setFreshness] = useState<MaturityLevel>(5); // Default to fresh
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    const shelfLife = await estimateShelfLife(name, freshness);
    const pDate = new Date(purchaseDate);
    const expiry = new Date(pDate);
    expiry.setDate(pDate.getDate() + shelfLife);

    const newItem: FoodItem = {
      id: crypto.randomUUID(),
      name: name.trim(),
      category,
      purchaseDate,
      expiryDate: expiry.toISOString().split('T')[0],
      maturity: freshness, // We store freshness level here
      estimatedShelfLifeDays: shelfLife,
      isUsed: false,
      isWasted: false,
      price: Math.floor(Math.random() * 8) + 3,
      weight: (Math.floor(Math.random() * 5) + 2) * 100,
    };

    onAdd(newItem);
    setLoading(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="bg-emerald-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">Ajouter un aliment</h2>
          <button onClick={onClose} className="p-2 hover:bg-emerald-500 rounded-full transition-colors">
            <i className="fa-solid fa-xmark text-lg"></i>
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto max-h-[80vh]">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-1">Nom du produit</label>
            <input
              autoFocus
              type="text"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all text-lg"
              placeholder="ex: Tomates, Lait..."
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mb-2">Catégorie</label>
            <div className="grid grid-cols-4 gap-2">
              {CATEGORIES.map((cat) => (
                <button
                  key={cat.label}
                  type="button"
                  onClick={() => setCategory(cat.label)}
                  className={`flex flex-col items-center justify-center p-2 rounded-xl border-2 transition-all ${
                    category === cat.label 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                      : 'border-slate-100 text-slate-400 grayscale opacity-60'
                  }`}
                >
                  <i className={`fa-solid ${cat.icon} text-lg mb-1`}></i>
                  <span className="text-[9px] font-bold leading-tight text-center">{cat.label}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Date d'achat</label>
              <input
                type="date"
                required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 text-sm outline-none focus:ring-2 focus:ring-emerald-500"
                value={purchaseDate}
                onChange={(e) => setPurchaseDate(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2 text-center">Fraîcheur</label>
              <div className="flex items-center gap-1 justify-center bg-slate-50 p-2 py-3 rounded-xl">
                {[1, 2, 3, 4, 5].map((level) => (
                  <button
                    key={level}
                    type="button"
                    onClick={() => setFreshness(level as MaturityLevel)}
                    className={`transition-all ${freshness >= level ? 'text-amber-400 scale-110' : 'text-slate-200'}`}
                  >
                    <i className="fa-solid fa-star text-sm"></i>
                  </button>
                ))}
              </div>
              <p className="text-[10px] text-center mt-1 text-slate-400 font-bold uppercase">
                {freshness === 5 ? 'Parfait' : freshness === 1 ? 'À utiliser' : 'Moyen'}
              </p>
            </div>
          </div>

          <button
            disabled={loading}
            type="submit"
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 rounded-2xl shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2 mt-4 active:scale-95"
          >
            {loading ? (
              <i className="fa-solid fa-circle-notch animate-spin"></i>
            ) : (
              <><i className="fa-solid fa-bolt"></i> AJOUTER MAINTENANT</>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

