                  <h3 className="font-bold text-slate-700 mb-1 text-lg">Frigo vide !</h3>
                  <p className="text-slate-400 text-sm">Ajoutez vos aliments pour commencer à économiser.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {sortedItems.map(item => (
                    <div key={item.id} className="bg-white rounded-3xl p-5 shadow-sm border border-slate-100 transition-all hover:shadow-md animate-in slide-in-from-bottom-6 duration-500">
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex gap-4">
                          <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 shrink-0">
                            <i className={`fa-solid ${getCategoryIcon(item.category)} text-xl`}></i>
                          </div>
                          <div>
                            <h3 className="font-black text-slate-800 text-lg capitalize leading-tight">{item.name}</h3>
                            <div className="flex items-center gap-1.5 mt-1">
                                <span className="text-[9px] font-black text-slate-300 uppercase tracking-tighter mr-1">Fraîcheur :</span>
                                {[1, 2, 3, 4, 5].map(lvl => (
                                    <i key={lvl} className={`fa-solid fa-star text-[9px] ${item.maturity >= lvl ? 'text-amber-400' : 'text-slate-100'}`}></i>
                                ))}
                            </div>
                          </div>
                        </div>
                        <div className={`px-3 py-1.5 rounded-xl text-white text-[10px] font-black uppercase tracking-wider ${getUrgencyColor(item.expiryDate)}`}>
                          {getUrgencyText(item.expiryDate)}
                        </div>
                      </div>

                      <div className="flex items-center gap-2 mt-2">
                        <button 
                          onClick={() => markAsUsed(item.id)}
                          className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl text-xs font-black flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100"
                        >
                          <i className="fa-solid fa-check-double"></i> CONSOMMÉ
                        </button>
                        <button 
                          onClick={() => setSelectedRecipeItem(item)}
                          className="w-12 h-12 bg-rose-50 text-rose-600 rounded-2xl flex items-center justify-center hover:bg-rose-100 transition-all border border-rose-100"
                        >
                          <i className="fa-solid fa-mortar-pestle"></i>
                        </button>
                        <button 
                          onClick={() => markAsWasted(item.id)}
                          className="w-12 h-12 bg-slate-50 text-slate-300 rounded-2xl flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 transition-all"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        )}

        {view === 'recipes' && (
          <div className="space-y-6">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2 mb-4">
              <i className="fa-solid fa-kitchen-set text-rose-500"></i> Recettes Anti-Gaspi
            </h2>

            {urgentItems.length > 0 ? (
              <div className="space-y-4">
                <p className="text-sm text-slate-500 bg-white p-5 rounded-3xl border border-slate-100 shadow-sm leading-relaxed">
