                {urgentItems.map(item => {
                  const daysLeft = Math.ceil((new Date(item.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
                  return (
                    <button 
                      key={item.id}
                      onClick={() => setSelectedRecipeItem(item)}
                      className="w-full text-left bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between hover:border-emerald-300 transition-all group"
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${daysLeft <= 2 ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                          <i className="fa-solid fa-utensils"></i>
                        </div>
                        <div>
                          <h4 className="font-bold text-slate-800 capitalize">{item.name}</h4>
                          <div className="flex items-center gap-2">
                             <span className="text-[9px] text-slate-400 font-black uppercase tracking-widest">{item.category}</span>
                             {daysLeft <= 2 && <span className="bg-rose-100 text-rose-600 text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Urgent</span>}
                          </div>
                        </div>
                      </div>
                      <i className="fa-solid fa-chevron-right text-slate-200 group-hover:translate-x-1 transition-all"></i>
                    </button>
