                <i className="fa-solid fa-face-smile text-amber-400 text-4xl mb-4"></i>
                <p className="text-slate-500 font-medium">Aucun aliment dans votre frigo.</p>
              </div>
            )}
          </div>
        )}

        {view === 'stats' && (
