                <div className="text-center py-10">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fa-solid fa-check text-slate-200 text-2xl"></i>
                  </div>
                  <p className="text-slate-400 font-bold">Rien à acheter pour l'instant.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[92%] max-w-sm glass rounded-[2.5rem] shadow-2xl p-2.5 flex justify-between items-center z-50 border border-white/50">
        <button 
          onClick={() => setView('home')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'home' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-refrigerator text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Frigo</span>
        </button>
        <button 
          onClick={() => setView('recipes')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'recipes' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-mortar-pestle text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Recettes</span>
        </button>
        <button 
          onClick={() => setView('list')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'list' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-cart-shopping text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Courses</span>
        </button>
        <button 
          onClick={() => setView('stats')}
          className={`flex-1 py-3.5 rounded-full flex flex-col items-center gap-1.5 transition-all ${view === 'stats' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100 scale-105' : 'text-slate-400 hover:text-emerald-500'}`}
        >
          <i className="fa-solid fa-chart-simple text-sm"></i>
          <span className="text-[8px] font-black uppercase tracking-widest">Impact</span>
        </button>
      </nav>

      {isAddModalOpen && (
        <AddFoodModal 
          onClose={() => setIsAddModalOpen(false)} 
          onAdd={handleAddItem} 
        />
      )}

      {selectedRecipeItem && (
        <RecipeModal 
          item={selectedRecipeItem} 
          otherIngredients={sortedItems.map(i => i.name)}
          onClose={() => setSelectedRecipeItem(null)} 
        />
      )}

      {isAdminOpen && (
        <AdminPanel 
          items={items} 
          stats={stats} 
          onClose={() => setIsAdminOpen(false)} 
          onRefresh={() => {
            setItems([]);
            setStats(loadStats());
          }} 
        />
      )}
    </div>
  );
};

