      if (!newTopWasted.includes(item.name)) newTopWasted.push(item.name);
      return {
        ...prev,
        wastedItemsCount: prev.wastedItemsCount + 1,
        topWastedItems: newTopWasted.slice(-5)
      };
    });
  };

  const handleResetApp = () => {
    if (window.confirm("Êtes-vous sûr de vouloir réinitialiser Zogdida ? Toutes vos données seront supprimées.")) {
      clearAllData();
      setItems([]);
      setStats({
        moneySaved: 0,
