export enum MaturityLevel {
  VERY_FRESH = 1,
  FRESH = 2,
  MATURE = 3,
  RIPE = 4,
  OVERRIPE = 5
}

export type FoodCategory = 'Légume' | 'Fruit' | 'Produit laitier' | 'Charcuterie' | 'Viande/Poisson' | 'Épicerie' | 'Autre';

export interface FoodItem {
  id: string;
  name: string;
  category: FoodCategory;
  purchaseDate: string;
  expiryDate: string;
  maturity: MaturityLevel;
  estimatedShelfLifeDays: number;
  isUsed: boolean;
  isWasted: boolean;
  price: number; // in TND
  weight: number; // in grams
}

export interface Recipe {
  title: string;
  ingredients: string[];
  steps: string[];
  duration: string;
  chefTip: string;
}

export interface DashboardStats {
  moneySaved: number;
  foodSavedWeight: number;
  wastedItemsCount: number;
  topWastedItems: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { MaturityLevel, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const estimateShelfLife = async (name: string, freshness: MaturityLevel): Promise<number> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Estime la durée de conservation restante (en jours) pour cet aliment : "${name}" avec un niveau de fraîcheur de ${freshness}/5 (5=parfaitement frais/neuf, 1=doit être consommé très rapidement). Réponds uniquement par un chiffre entier.`,
    });
    const days = parseInt(response.text.trim());
    return isNaN(days) ? 3 : days;
  } catch (error) {
    console.error("Error estimating shelf life:", error);
    return 3;
  }
};

export const getRecipes = async (itemName: string, otherIngredients: string[]): Promise<Recipe[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Propose 3 recettes rapides et faciles (moins de 20 min) mettant en valeur l'ingrédient principal : "${itemName}". Propose des recettes variées et gourmandes. Autres ingrédients éventuellement disponibles : ${otherIngredients.join(", ")}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
              steps: { type: Type.ARRAY, items: { type: Type.STRING } },
              duration: { type: Type.STRING },
              chefTip: { type: Type.STRING }
            },
            required: ["title", "ingredients", "steps", "duration", "chefTip"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Error fetching recipes:", error);
    return [];
  }
};

