interface RecipeModalProps {
  item?: FoodItem;
  customItems?: FoodItem[];
  otherIngredients: string[];
  onClose: () => void;
}

const RecipeModal: React.FC<RecipeModalProps> = ({ item, customItems, otherIngredients, onClose }) => {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
