                className={`w-11 h-11 rounded-2xl border-2 flex items-center justify-center transition-all active:scale-90 ${isSelectionMode ? 'bg-rose-500 border-rose-500 text-white shadow-lg shadow-rose-200' : 'bg-white border-slate-100 text-slate-400 shadow-sm'}`}
